import{c as d,a7 as e,y as r,B as a}from"./chunks/framework.3cjvm90C.js";const m=JSON.parse('{"title":"MindSpeed 训练加速库概览","description":"介绍昇腾 MindSpeed 训练加速库的整体架构，包括 Core 加速模块、LLM 套件、MM 套件及 RL 套件的核心特性与加速能力","frontmatter":{"title":"MindSpeed 训练加速库概览","description":"介绍昇腾 MindSpeed 训练加速库的整体架构，包括 Core 加速模块、LLM 套件、MM 套件及 RL 套件的核心特性与加速能力"},"headers":[],"relativePath":"ascend/mindspeed.md","filePath":"ascend/mindspeed.md","lastUpdated":1782447613000}'),i={name:"ascend/mindspeed.md"};function n(l,t,o,s,h,p){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="mindspeed-训练加速库概览" tabindex="-1">MindSpeed 训练加速库概览 <a class="header-anchor" href="#mindspeed-训练加速库概览" aria-label="Permalink to “MindSpeed 训练加速库概览”">​</a></h1><p>MindSpeed 是一款专为昇腾平台打造的高性能训练加速库，涵盖 MindSpeed Core 亲和加速模块、MindSpeed LLM 套件、MindSpeed MM 套件以及 MindSpeed RL 套件四个核心组件。基于昇腾硬件的分布式训练加速能力，提供多维度加速算法，支持主流大语言模型与多模态大模型，面向大模型全流程加速。</p><p><img src="https://www.hiascend.com/doc_center/source/zh/MindSpeed/220/productoverview/figure/zh-cn_image_0000002501882927.png" alt="MindSpeed 整体架构"></p><h2 id="组件一览" tabindex="-1">组件一览 <a class="header-anchor" href="#组件一览" aria-label="Permalink to “组件一览”">​</a></h2><table tabindex="0"><thead><tr><th>组件名称</th><th>说明</th></tr></thead><tbody><tr><td>MindSpeed Core</td><td>基于昇腾设备的大模型加速模块，提供计算、内存、通信、并行四个维度的优化，支持长序列、MoE 等场景加速特性。</td></tr><tr><td>MindSpeed LLM</td><td>大语言模型套件，提供端到端的训练方案，包含分布式预训练、指令微调及配套工具链，覆盖业内主流大语言模型。</td></tr><tr><td>MindSpeed MM</td><td>多模态大模型套件，聚焦多模态生成与理解，提供端到端训练流程，支持图文理解、图像生成、视频生成等场景。</td></tr><tr><td>MindSpeed RL</td><td>强化学习套件，提供超大集群训推共卡、异步流水调度、训推异构切分通信等核心加速能力。</td></tr></tbody></table><h2 id="mindspeed-core-亲和加速模块" tabindex="-1">MindSpeed Core 亲和加速模块 <a class="header-anchor" href="#mindspeed-core-亲和加速模块" aria-label="Permalink to “MindSpeed Core 亲和加速模块”">​</a></h2><p>针对昇腾设备推出的亲和加速模块，提供多维度加速算法：</p><ul><li><strong>并行算法优化</strong>：支持模型并行、优化器并行、专家并行、长序列并行等多维并行策略，针对昇腾软硬件架构进行亲和优化。</li><li><strong>内存资源优化</strong>：提供内存压缩、复用、内存交换以及差异化的重计算技术，最大限度利用内存资源。</li><li><strong>通信性能优化</strong>：采用通算融合、通算掩盖等策略，配合高效的算网协同机制，大幅提高算力利用率。</li><li><strong>计算性能优化</strong>：集成高性能融合算子库，结合昇腾亲和的计算优化，充分释放昇腾算力。</li></ul><h2 id="mindspeed-llm-套件" tabindex="-1">MindSpeed LLM 套件 <a class="header-anchor" href="#mindspeed-llm-套件" aria-label="Permalink to “MindSpeed LLM 套件”">​</a></h2><p>针对昇腾硬件推出的大语言模型套件，提供开箱即用的主流开源大模型：</p><ul><li><strong>主流 LLM 模型</strong>：支持 Qwen3/DeepSeek/Mamba2 系列等 100+ 主流 LLM 模型，涵盖 Dense/MoE/SSM 等架构。</li><li><strong>分布式预训练</strong>：提供数据预处理方案与包含 TP/PP/DP/CP/EP 在内的多维并行策略。</li><li><strong>分布式指令微调</strong>：支持全参微调/LoRA/QLoRA 微调训练算法，并提供性能/显存优化手段。</li><li><strong>模型权重转换</strong>：支持 Megatron/HuggingFace 格式的权重转换和 LoRA 微调权重的独立/合并转换。</li><li><strong>在线推理与评估</strong>：支持模型分布式在线推理与公版数据的在线评估。</li></ul><h2 id="mindspeed-mm-套件" tabindex="-1">MindSpeed MM 套件 <a class="header-anchor" href="#mindspeed-mm-套件" aria-label="Permalink to “MindSpeed MM 套件”">​</a></h2><p>针对昇腾硬件推出的多模态模型套件，支持多模态模型开发全流程：</p><ul><li><strong>主流多模态模型</strong>：支持 LLaVA/InternVL/QwenVL 系列（理解）、OpenSoraPlan/CogVideoX/HunyuanVideo/Wan2.1 系列（视频生成）、SDXL/FLUX/SANA 系列（文生图）。</li><li><strong>分布式训练</strong>：支持异构 PP/TP/SP 等多维并行策略，通过细粒度选择性重计算和 Async-offload 异步卸载技术实现超长序列性能优化。</li><li><strong>LoRA 与 DPO</strong>：支持 LoRA 微调和 DPO 训练。</li></ul><h2 id="mindspeed-rl-套件" tabindex="-1">MindSpeed RL 套件 <a class="header-anchor" href="#mindspeed-rl-套件" aria-label="Permalink to “MindSpeed RL 套件”">​</a></h2><p>针对昇腾硬件推出的强化学习开发套件，提供端到端的 RL 后训练解决方案：</p><ul><li><strong>训推共卡</strong>：支持训推最优并行的共卡切换及精细化的训推内存管理技术。</li><li><strong>计算流编排优化</strong>：支持异步 Replay Buffer，解耦数据依赖，使能异步训练与任务流水掩盖。</li><li><strong>负载均衡优化</strong>：支持变长序列的数据负载均衡，显著提升算力利用率。</li><li><strong>大规模 RL 优化</strong>：支持千亿 MoE 长序列的高性能训练。</li></ul><h2 id="加速特性总览" tabindex="-1">加速特性总览 <a class="header-anchor" href="#加速特性总览" aria-label="Permalink to “加速特性总览”">​</a></h2><h3 id="训练加速特性" tabindex="-1">训练加速特性 <a class="header-anchor" href="#训练加速特性" aria-label="Permalink to “训练加速特性”">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>特性名称</th><th>说明</th></tr></thead><tbody><tr><td>长序列</td><td>Ring Attention</td><td>Megatron-Ring 算法实现</td></tr><tr><td>长序列</td><td>Ulysses</td><td>DeepSpeed-Ulysses 算法实现</td></tr><tr><td>长序列</td><td>混合长序列并行</td><td>结合 Ring 和 Ulysses 的长序列算法</td></tr><tr><td>长序列</td><td>Adaptive-CP</td><td>序列重映射寻优与调度寻优</td></tr><tr><td>显存与计算均衡</td><td>Noop Layer</td><td>插入空操作层均衡 PP Stage 计算，减少流水并行空泡</td></tr><tr><td>显存与计算均衡</td><td>Dynamic PP</td><td>手动指定 PP Stage 层数，均衡内存与计算</td></tr><tr><td>MoE</td><td>All-Gather Dispatcher 优化</td><td><code>--moe-permutation-async-comm --moe-token-dispatcher-type allgather</code></td></tr><tr><td>MoE</td><td>All2All Dispatcher 优化</td><td><code>--moe-permutation-async-comm --moe-token-dispatcher-type alltoall</code></td></tr><tr><td>通算掩盖</td><td>MC2</td><td>TP SP 场景对线性层做通算掩盖</td></tr><tr><td>通算掩盖</td><td>梯度 Reduce 通算掩盖</td><td>梯度更新与 Reduce 通算掩盖</td></tr><tr><td>通信优化</td><td>高维张量并行</td><td>切分传统 1D-TP 通信域，提升 TP 通信效率</td></tr></tbody></table><h3 id="显存优化特性" tabindex="-1">显存优化特性 <a class="header-anchor" href="#显存优化特性" aria-label="Permalink to “显存优化特性”">​</a></h3><table tabindex="0"><thead><tr><th>特性名称</th><th>说明</th></tr></thead><tbody><tr><td>参数副本复用</td><td>显存时分复用，计算参数与参数副本</td></tr><tr><td>分布式优化器</td><td>将优化器状态在 DP 域上拆分</td></tr><tr><td>Swap Attention</td><td>利用设备内存存放激活值</td></tr><tr><td>激活函数重计算</td><td>对激活函数做重计算，节省内存</td></tr><tr><td>O2 BF16 Optimizer</td><td>使用半精度优化器参数与梯度</td></tr></tbody></table><h3 id="融合算子" tabindex="-1">融合算子 <a class="header-anchor" href="#融合算子" aria-label="Permalink to “融合算子”">​</a></h3><table tabindex="0"><thead><tr><th>融合算子名称</th><th>应用场景</th></tr></thead><tbody><tr><td>Flash Attention</td><td>通用</td></tr><tr><td>Fused Ring Attention Update</td><td>长序列 CP-Ring 算法</td></tr><tr><td>Fused Token Permute/Unpermute</td><td>MoE All2All Dispatcher Dropless</td></tr><tr><td>GMM</td><td>MoE 小专家</td></tr><tr><td>Matmul Add</td><td>稠密模型梯度累积</td></tr><tr><td>Fused SwiGLU</td><td>通用</td></tr><tr><td>Fused Rotary Position Embedding</td><td>通用</td></tr><tr><td>Fused RMSNorm</td><td>通用</td></tr></tbody></table><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to “延伸阅读”">​</a></h2><ul><li><a href="/llmtechsite/ascend/mindspeed_llm">MindSpeed-LLM 性能优化方法论</a></li><li><a href="/llmtechsite/ascend/mindspeed_llm_guide">MindSpeed-LLM 使用指南</a></li><li><a href="/llmtechsite/ascend/mindspeed_rl_guide">MindSpeed-RL 使用教程</a></li><li><a href="/llmtechsite/ascend/long_context_length">长上下文序列训练方案</a></li></ul>',26)])])}const M=d(i,[["render",n]]);export{m as __pageData,M as default};
